sql.trim:
a.store_id = #{store_id} and a.recycle=0 and a.oType='ZB'


        #{status,jdbcType=INTEGER}


and a.mch_id like concat(',',#{mch_id},',')
and a.add_time   >=   #{startTime}
and a.add_time   <=   #{endTime}
and (a.sNo like concat('%',#{keyWord},'%') or m.name like concat('%',#{keyWord},'%') or u.user_id like concat('%',#{keyWord},'%')
or u.user_name like concat('%',#{keyWord},'%') or a.name like concat('%',#{keyWord},'%') or r.living_theme like concat('%',#{keyWord},'%') or r.id like concat('%',#{keyWord},'%'))

mapper.select:
select a.*,r.id as roomId,r.living_theme as title,m.logo,d.commission from lkt_order a RIGHT JOIN lkt_order_details d ON a.sNo = d.r_sNo LEFT JOIN lkt_product_list as p on p.id = d.p_id left join lkt_living_room r on d.living_room_id = r.id left join lkt_mch m on m.id = p.mch_id left join lkt_user u on a.user_id = u.user_id
order by add_time desc
limit #{pageNo},#{pageSize}

